import "container/heap"

func solve(value []int64, limit []int64) int64 {
    n := len(value)
    // Use a priority queue to always activate the element with the highest value
    // Each element is stored as (-value[i], limit[i], i) to simulate a max-heap
    type Item struct {
        val   int64
        lim   int64
        index int
    }
    h := make([]Item, n)
    for i := range h {
        h[i] = Item{value[i], limit[i], i}
    }
    heap.Init(&h)

    total := int64(0)
    activeCount := int64(0)

    for h != nil {
        item := heap.Pop(&h).(Item)
        if activeCount < item.lim {
            total += -item.val
            activeCount++
            // After activation, check which elements become inactive
            // We cannot remove them from the heap, so we just ignore them in the next steps
        }
    }

    return total
}
